#include <stdio.h>
#include <stdlib.h>

void rearrangeArray(int *arr, int n) {
    int half = n/2;
    int *pos = (int*)malloc(half * sizeof(int));
    int *neg = (int*)malloc(half * sizeof(int));
    int p=0,q=0;
    for(int i=0;i<n;++i){
        if(arr[i]>0) pos[p++]=arr[i];
        else neg[q++]=arr[i];
    }
    for(int i=0;i<half;++i){
        arr[2*i]=pos[i];
        arr[2*i+1]=neg[i];
    }
    free(pos);
    free(neg);
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *arr = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;++i) scanf("%d",&arr[i]);
        rearrangeArray(arr,N);
        for(int i=0;i<N;++i){
            if(i) printf(" ");
            printf("%d",arr[i]);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

