#include <bits/stdc++.h>
using namespace std;

void rearrangeArray(vector<int>& a){
    int n=a.size();
    int half=n/2;
    vector<int> pos; pos.reserve(half);
    vector<int> neg; neg.reserve(half);
    for(int x:a){
        if(x>0) pos.push_back(x);
        else neg.push_back(x);
    }
    for(int i=0;i<half;++i){
        a[2*i]=pos[i];
        a[2*i+1]=neg[i];
    }
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> a(N);
        for(int &x:a) cin>>x;
        rearrangeArray(a);
        for(int i=0;i<N;++i){
            if(i) cout<<' ';
            cout<<a[i];
        }
        cout<<'\n';
    }
    return 0;
}

